I have this notification banner component that uses React Native's Animated API. Convert it to use a better animation approach — it should slide in from the top and fade in when shown:

```tsx
import React, { useEffect, useRef } from 'react';
import { Animated, View, Text } from 'react-native';

export function NotificationBanner({ message, visible }: { message: string; visible: boolean }) {
  const slideAnim = useRef(new Animated.Value(-60)).current;
  const opacityAnim = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    if (visible) {
      Animated.parallel([
        Animated.timing(slideAnim, { toValue: 0, duration: 300, useNativeDriver: true }),
        Animated.timing(opacityAnim, { toValue: 1, duration: 300, useNativeDriver: true }),
      ]).start();
    } else {
      Animated.parallel([
        Animated.timing(slideAnim, { toValue: -60, duration: 200, useNativeDriver: true }),
        Animated.timing(opacityAnim, { toValue: 0, duration: 200, useNativeDriver: true }),
      ]).start();
    }
  }, [visible]);

  return (
    <Animated.View style={{ transform: [{ translateY: slideAnim }], opacity: opacityAnim }}>
      <View className="bg-black px-4 py-3 rounded-xl">
        <Text className="text-white text-sm">{message}</Text>
      </View>
    </Animated.View>
  );
}
```
